namespace sv_214e23db5b5841fd86726c1bb8648a7d.Client.Models;

public class Shipment
{
    public required string TrackingNumber { get; set; }
    public required string Status { get; set; }
    public required string Location { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public List<StatusUpdate> StatusUpdates { get; set; } = [];
}

public class StatusUpdate
{
    public required string Description { get; set; }
    public DateTime Timestamp { get; set; }
}

using sv_214e23db5b5841fd86726c1bb8648a7d.Client.Models;

namespace sv_214e23db5b5841fd86726c1bb8648a7d.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_214e23db5b5841fd86726c1bb8648a7d.Client.Models;
using sv_214e23db5b5841fd86726c1bb8648a7d.Client.Services;

namespace sv_214e23db5b5841fd86726c1bb8648a7d.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> Shipments = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTime(2026, 6, 3, 17, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTime(2026, 5, 27, 9, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Departed facility in New York, NY", Timestamp = new DateTime(2026, 5, 27, 14, 30, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Arrived at sorting center in Chicago, IL", Timestamp = new DateTime(2026, 5, 28, 6, 15, 0, DateTimeKind.Utc) },
            ]
        },
        ["PKG-002"] = new Shipment
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTime(2026, 5, 26, 12, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTime(2026, 5, 23, 10, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "In transit to destination", Timestamp = new DateTime(2026, 5, 24, 8, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Out for delivery", Timestamp = new DateTime(2026, 5, 26, 7, 30, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Delivered — signed by J. Smith", Timestamp = new DateTime(2026, 5, 26, 11, 45, 0, DateTimeKind.Utc) },
            ]
        },
        ["PKG-003"] = new Shipment
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Seattle, WA",
            EstimatedDelivery = new DateTime(2026, 6, 5, 18, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Order received", Timestamp = new DateTime(2026, 5, 28, 16, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Label created", Timestamp = new DateTime(2026, 5, 28, 16, 5, 0, DateTimeKind.Utc) },
            ]
        },
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        Shipments.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using System.Net.Http.Json;
using sv_214e23db5b5841fd86726c1bb8648a7d.Client.Models;

namespace sv_214e23db5b5841fd86726c1bb8648a7d.Client.Services;

public class ShipmentServiceClient(HttpClient http) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
        {
            return null;
        }

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

@page "/shipments/{TrackingNumber}"
@using sv_214e23db5b5841fd86726c1bb8648a7d.Client.Models
@using sv_214e23db5b5841fd86726c1bb8648a7d.Client.Services
@rendermode InteractiveAuto
@implements IAsyncDisposable
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="alert alert-info" role="status">
        <span class="spinner-border spinner-border-sm me-2" aria-hidden="true"></span>
        Loading shipment <strong>@TrackingNumber</strong>&hellip;
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="alert alert-warning" role="alert">
        No shipment found for tracking number <strong>@TrackingNumber</strong>.
    </div>
}
else
{
    <h2>Shipment @_shipment.TrackingNumber</h2>

    <dl class="row">
        <dt class="col-sm-3">Status</dt>
        <dd class="col-sm-9">@_shipment.Status</dd>

        <dt class="col-sm-3">Location</dt>
        <dd class="col-sm-9">@_shipment.Location</dd>

        <dt class="col-sm-3">Estimated Delivery</dt>
        <dd class="col-sm-9">
            @(_shipment.EstimatedDelivery?.ToString("f") ?? "Unknown")
        </dd>
    </dl>

    @if (_shipment.StatusUpdates.Count > 0)
    {
        <h4>Status History</h4>
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Time</th>
                    <th>Event</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in _shipment.StatusUpdates.OrderByDescending(u => u.Timestamp))
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Description</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource _cts = new();
    private string? _lastLoadedTrackingNumber;

    protected override Task OnParametersSetAsync()
    {
        if (string.Equals(_lastLoadedTrackingNumber, TrackingNumber, StringComparison.OrdinalIgnoreCase))
        {
            return Task.CompletedTask;
        }

        return LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any previous in-flight request
        await _cts.CancelAsync();
        _cts.Dispose();
        _cts = new CancellationTokenSource();

        _lastLoadedTrackingNumber = TrackingNumber;
        _shipment = null;
        _errorMessage = null;
        _loading = true;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, _cts.Token);
        }
        catch (OperationCanceledException)
        {
            // Request was canceled (navigation change or disposal) — nothing to show.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading the shipment. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private Task RetryAsync() => LoadShipmentAsync();

    public async ValueTask DisposeAsync()
    {
        await _cts.CancelAsync();
        _cts.Dispose();
    }
}

